content:
/* Minor PAQ-flavoured tweaks layered on top of the bslib theme. */

.card-header {
  font-weight: 600;
  color: #001056; /* PAQ night blue */
}

.value-box .value-box-title {
  font-size: 0.85rem;
}

/* Optimum cell greyed when the matching weight is 0 (does nothing). */
.opt-cell { margin-bottom: 0.5rem; }
.opt-disabled { opacity: 0.4; }

/* Sidebar live score distribution: stays in view while the page scrolls. */
.side-dist { position: sticky; top: 0.5rem; }

/* Keep the score tables compact. */
table.dataTable td, table.dataTable th {
  padding: 4px 8px;
  font-size: 0.85rem;
}
